package com.trademaster.ims.mobile.orders.model;
import jakarta.persistence.*;
@Entity @Table(name="customer_return_request_items",indexes={@Index(name="idx_return_item_request",columnList="return_request_id"),@Index(name="idx_return_item_order_item",columnList="order_item_id")})
public class CustomerReturnRequestItem{public enum ReasonCode{DAMAGED_OR_DEFECTIVE,WRONG_ITEM,NOT_AS_DESCRIBED,MISSING_PARTS,CHANGED_MIND,OTHER}@Id @GeneratedValue(strategy=GenerationType.IDENTITY)private Long id;@Column(name="return_request_id",nullable=false)private Long returnRequestId;@Column(name="order_item_id",nullable=false)private Long orderItemId;@Column(name="requested_quantity",nullable=false)private int requestedQuantity;@Column(name="approved_quantity")private Integer approvedQuantity;@Enumerated(EnumType.STRING)@Column(name="reason_code",nullable=false,length=40)private ReasonCode reasonCode;@Column(name="reason_text",length=500)private String reasonText;public Long getId(){return id;}public Long getReturnRequestId(){return returnRequestId;}public Long getOrderItemId(){return orderItemId;}public int getRequestedQuantity(){return requestedQuantity;}public ReasonCode getReasonCode(){return reasonCode;}public String getReasonText(){return reasonText;}public void setReturnRequestId(Long v){returnRequestId=v;}public void setOrderItemId(Long v){orderItemId=v;}public void setRequestedQuantity(int v){requestedQuantity=v;}public void setReasonCode(ReasonCode v){reasonCode=v;}public void setReasonText(String v){reasonText=v;}}
